-- IN — busca toda a lista antes de comparar
SELECT Nome FROM Clientes
WHERE Id IN (SELECT ClienteId FROM Pedidos);

-- EXISTS — para quando encontra o primeiro match (mais eficiente)
SELECT Nome FROM Clientes c
WHERE EXISTS (
    SELECT 1 FROM Pedidos p
    WHERE p.ClienteId = c.Id
);
-- Nota: SELECT 1 é convencional — EXISTS só verifica existência, não o valor
